var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"미리네 씨, 여기예요…! 다행히 모두 무사하셨군요……!","JPN":"マリさん、ここです……！　よかった、無事だったんですね……！","ENG":"Ms. Mi Rinae, over here...! Thank goodness, you're all safe...!","TWN":"宓璃奈，這裡…！幸好大家都平安無事……！"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L6_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"아하하, 내 한 발 늦었나?","JPN":"あはは、一足遅れちゃったんか？","ENG":"Ahaha, guess I showed up a bit late?","TWN":"啊哈哈，我是不是慢了一步？"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"종자님께서 곧 수송기를 보낸다고 하셨어요. 조금만 기다리면 시니어님을 모시고……","JPN":"従者様がもうすぐ輸送機を送るそうです。あと少しで、シニアを連れて……","ENG":"Squire said a transport will be dispatched soon. Once it arrives, we'll bring the Senior...","TWN":"手下說很快就會派運輸機過來。再等一下就能把Senior接……"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"으음?","JPN":"ん？","ENG":"Mm?","TWN":"嗯？"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L10_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"저… 혹시 시니어님께서는…….","JPN":"あの……もしかして、シニアは……","ENG":"Wait... the Senior...","TWN":"……Senior……"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_NULL_ON","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_NULL_ON","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"시니어 칸께서는 운명을 달리하셨습니다.","JPN":"シニア・カンは永い眠りにつかれました。","ENG":"Senior Khan has passed away.","TWN":"Senior已經離世。"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_NULL_ON","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"하지만 돌아가시기 전에 자신의 모든 권한을 시타 아가씨께 맡기셨어요.","JPN":"ですが、亡くなる前にご自身のすべての権限をシータお嬢様に託されました。","ENG":"But before his death, he entrusted all his authority to Lady Sita.","TWN":"但是在去世之前，他將自己所有的權限都移交悉多小姐。"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_NULL_ON","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"따라서 지금은 시타 아가씨께서 캄파멘토의 시니어입니다.","JPN":"よって、現在はシータお嬢様がカンパメントのシニアです。","ENG":"As of now, Lady Sita is the Senior of Campamento.","TWN":"因此，現在是悉多小姐就是坎帕門托的Senior。"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_NULL_ON","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"그, 그렇군요…….","JPN":"そ、そうなんですね……","ENG":"I-I see...","TWN":"原，原來如此……"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"자자, 다들 얼굴 좀 펴이소.","JPN":"まあまあ、みんな湿気た顔せんとき。","ENG":"Come on, everyone, don't look so down.","TWN":"好了好了，大家都笑一笑。"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"슬퍼하는 건, 나중에 해도 충분합니데이.","JPN":"悲しむのは後でも十分やろ。","ENG":"There'll be plenty of time to grieve later.","TWN":"傷心的事，晚點再說吧。"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"살아 있는 사람은, 살아가는 게 먼저 아이겠습니까.","JPN":"生きてる人間は、生きなあかんねん。","ENG":"For the living, survival comes first.","TWN":"活著的人，活下去才是最重要的，不是嗎？"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"지금은… 이 섬에서 빠져나가가, 캄파멘토의 상황을 알리는 게 먼저입니다.","JPN":"今は…この島を抜け出して、カンパメントの状況を知らせることが優先や。","ENG":"Right now, escaping this island and reporting to Campamento is the priority.","TWN":"現在……首先是要從這個島上逃出去，將坎帕門托的情況告知大家。"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"그러니까……","JPN":"だから……","ENG":"So...","TWN":"所以……"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"지, 지진……?","JPN":"じ、地震……？","ENG":"A-an earthquake...?","TWN":"地，地震……？"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"설마, 또 데몰리션 웜이 나타나는 걸까요?","JPN":"まさか、またデモリッションワームが現れるのでしょうか？","ENG":"Don't tell me it's another Demolition Worm!","TWN":"難道又是爆破蠕蟲？"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"아이다! 이건 지진이 아니고, 공간 자체가 떨리고 있는기다……!","JPN":"ちゃう！　これは地震じゃない、空間自体が揺れてるんや……！","ENG":"No! This isn't a quake. The space itself is shaking...!","TWN":"哎呀！這不是地震，而是空間本身在震動……！"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"공간이 떨린다고요?","JPN":"空間が揺れる？","ENG":"Space is shaking?","TWN":"空間在震動嗎？"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_NULL_ON","text":{"KOREA":"찬란하게 빛나는 태양이 나무뿌리에 가려, 그 빛을 잃어버리게 될 때.","JPN":"燦々と輝く太陽が木の根に隠れ、その光を失う時。","ENG":"When the radiant sun is veiled by roots, its light fading away...","TWN":"當璀璨耀眼的陽光被樹根遮蔽而失去光芒之時，"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_ON","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_NULL_ON","text":{"KOREA":"하늘이 갈라지며 땅과 구름이 맞닿는 곳, 어딘가 황금의 도시가 모습을 드러내고.","JPN":"天が切り裂かれ、地と雲が交わる場所、そのどこかに黄金の都市が姿を現し、","ENG":"The heavens will split open, and where earth and cloud meet, a golden city will appear.","TWN":"天空將會裂開，在大地與雲彩交會的地方，黃金城將現身。  "},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_NULL_ON","text":{"KOREA":"그곳, 황금향이 남긴 유산이 수많은 이들을 구하게 되리라.","JPN":"かの地、黄金郷が残した遺産が多くの者を救うであろう。","ENG":"There, the Golden Vale's Legacy will save countless lives.","TWN":"黃金城留下的寶藏，將拯救無數的人。  "},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_NULL_ON","text":{"KOREA":"전설대로라면… 지금이 그 때일지도 몰라요…….","JPN":"伝説通りなら……今がその時なのかもしれません……","ENG":"If the legend is true... this might be that moment...","TWN":"如果傳說是真的……現在可能就是那個時候……"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_ON","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"뭐, 뭐라고예?","JPN":"な、なんやと？","ENG":"W-what did you say?","TWN":"你，你說什麼？"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"두 분 다 거기서 피하세요……!","JPN":"二人とも、そこから逃げて……！","ENG":"Both of you, get back...!","TWN":"你們兩個，快從那裡躲開……！"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L47_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"이, 이게 뭐고? 진짜로 대균열에서 나무뿌리가 뻗어나왔다고……?","JPN":"な、何やこれ？　ホンマに大亀裂から木の根が伸びてきたで……？","ENG":"W-what the–? Roots are spreading out from the Grand Dimension Crevice itself?!","TWN":"這，這是啥？真的有樹根從大峽谷中竄出來……？"},"stage":{"bg":"OMEN_CAMPAMENTO_01","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SURPRISE"}}}},{"id":"L48_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"그, 그럼 이제 우리는 어쩌죠?","JPN":"こ、これから、一体どうなるのでしょう？","ENG":"Then what do we do now...?","TWN":"那，那我們現在該怎麼辦呢？"},"stage":{"bg":"OMEN_CAMPAMENTO_01","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"전설대로 세계가 멸망하게 되는 걸까요?","JPN":"伝説通り、世界は滅んでしまうんですか？","ENG":"Is the world really going to end, just like the legend?","TWN":"難道真的會如傳說中那樣，世界將要毀滅嗎？"},"stage":{"bg":"OMEN_CAMPAMENTO_01","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"글쎄다? 그래도 도망칠 수 있는 데까지는 도망쳐 봐야 하지 않겠나?","JPN":"さあ？　でも逃げられるとこまでは逃げてみるしかないやろ？","ENG":"Who knows? Either way, we run as far as we can.","TWN":"不知道呢？不過還是要儘量逃遠點吧。"},"stage":{"bg":"OMEN_CAMPAMENTO_01","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_NULL_ON","text":{"KOREA":"보세요! 나무뿌리가 이 천공섬 전체를 뒤덮고 있어요!","JPN":"見てください！　木の根がこの天空島全体を覆っています！","ENG":"Look! The roots are covering the whole island!","TWN":"你們看！樹根覆蓋住整個天空島！"},"stage":{"bg":"OMEN_CAMPAMENTO_01","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_ON","face":"UNIT_IDLE"},"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_NULL_ON","text":{"KOREA":"뒤덮이는 속도가 빨라요! 이대로 가다간 곧 이곳도 나무뿌리로……","JPN":"伸びる速度が速すぎます！　このままだと、ここも木の根に……","ENG":"It's spreading fast! At this rate, we'll be engulfed–","TWN":"覆蓋的速度好快！照這樣下去，這裡也很快就會被樹根……"},"stage":{"bg":"OMEN_CAMPAMENTO_01","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_ON","face":"UNIT_IDLE"},"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_NULL_ON","text":{"KOREA":"음!?","JPN":"え！？","ENG":"Mm?!","TWN":"嗯！？"},"stage":{"bg":"OMEN_CAMPAMENTO_01","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_ON","face":"UNIT_SURPRISE"},"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"저건…! 얌, 뭐시라카는 거대종 침식체……!","JPN":"あれは……！　ユムなんちゃらって巨大種侵食体……！","ENG":"That's...! That colossal C.O., Yam-something...!","TWN":"那是……！那個姆什麼的巨大種侵蝕體……！"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"엎친 데 덮친 격이라 아이가…! 하필이면 이럴 때 침식체까지……!","JPN":"まったく泣き面に蜂やな……！　よりによってこんな時に侵食体まで……！","ENG":"Couldn't get any worse, huh? Even a C.O. now?!","TWN":"真是雪上加霜……！偏偏在這個時候連侵蝕體也來攪和……！"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"자, 잠깐만요! 미리네 씨!","JPN":"ま、待ってください、マリさん！","ENG":"W-wait, Ms. Mi Rinae!","TWN":"等，等一下！宓璃奈！"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"얌 카악스의 행동이 뭔가 이상해요!","JPN":"ユム・カアシュの行動がどこか変です！","ENG":"Yam Kaax is acting strange!","TWN":"姆卡許的行為有些奇怪！"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_NULL_ON","text":{"KOREA":"치, 침식체가…….","JPN":"し、侵食体が……","ENG":"Th-the C.O...","TWN":"侵，侵蝕體……"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_NULL_ON","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"침식체가… 나무뿌리로부터 우리를 지켜주고 있어요…….","JPN":"侵食体が……木の根から私たちを守っています……","ENG":"The C.O... it's shielding us from the roots...","TWN":"侵蝕體……在保護我們不被樹根攻擊……"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_NULL_ON","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"말도 안 돼. 대체 어째서……?","JPN":"ありえない。いったいなぜ……？","ENG":"Impossible. Why would it do that...?","TWN":"不可能，這到底是為什麼……？"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_NULL_ON","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_NULL_ON","text":{"KOREA":"이건……?","JPN":"これは……？","ENG":"This is...?","TWN":"這是……？"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_NULL_ON","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"이유야 어찌 됐든, 침식체가 뿌리를 막고 있는 지금이 기회입니다!","JPN":"理由はともあれ、侵食体が根を食い止めてる今がチャンスや！","ENG":"Whatever the reason, while the C.O.'s blocking the roots is our chance!","TWN":"不管原因是啥，趁著侵蝕體擋住樹根，我們要把握機會！"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"어서 이곳에서 대피해야……!","JPN":"早よここから逃げへんと……！","ENG":"We need to evacuate now...!","TWN":"快點從這裡撤離……！"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"TITAN_FAW_HYERION_QM","text":{"KOREA":"헬리오스 시스템 기동. 안티 그래비티 필드 전개.","JPN":"ヘリオスシステム起動。アンチグラビティフィールド展開。","ENG":"Helios System, activated. Anti-gravity field deployed.","TWN":"雷射系統啟動，展開反重力場域。"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L30_1","type":"dialog","speaker":"TITAN_FAW_HYERION_QM","text":{"KOREA":"지금부터 대균열의 반중력장을 돌파하겠다!","JPN":"只今より大亀裂の反重力場を突破する！","ENG":"Commencing breakthrough of the Grand Dimension Crevice's anti-gravity field!","TWN":"現在開始突破大峽谷的反重力場域！"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"서, 설마, 이 회선은……!?","JPN":"ま、まさか、この回線は……！？","ENG":"N-no way, this comm line...!","TWN":"難，難道，這條線路是……？"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"아하! 쌤이 보내기로 한 수송선이가……!","JPN":"ああ、先生が送るって言うてたん輸送機か……！","ENG":"A-ha! That must be the transport Teach promised...!","TWN":"啊哈！老師要送來的運輸船是……！"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"TITAN_FAW_HYERION_QM","text":{"KOREA":"하하하! 이 몸의 새로운 프레임을 보고도 고작 수송선이라니!","JPN":"ははは！　吾輩の新たなフレームを目にして、たかが輸送機とは！","ENG":"Ha ha ha! To call this new frame of mine a mere transport!","TWN":"哈哈哈！看到我的新軀殼，居然還以為只是運輸船嗎！"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"TITAN_FAW_HYERION_QM","text":{"KOREA":"재미있는 발상이로군! 하지만 잘못 보았네!","JPN":"面白い発想だな！　残念ながら大間違いだ！","ENG":"What an amusing notion! But mistaken nonetheless!","TWN":"真是有趣的想法！不過你可看走眼囉！"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"TITAN_FAW_HYERION_NULL","text":{"KOREA":"대륙간 전략 공중 요새, 히페리온 여기 도착!","JPN":"大陸間戦略空中要塞ハイペリオン、ただいま参上！","ENG":"Intercontinental Strategic Aerial Fortress, Hyperion now arriving!","TWN":"大陸戰略空中要塞，海柏利昂抵達！"},"stage":{"bg":"SKY_RED","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_HYERION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"TITAN_FAW_HYERION_NULL","text":{"KOREA":"지금부터 작전 구역 일대에 전략 폭격을 시작한다!","JPN":"これより作戦区域一帯に戦略爆撃を開始する！","ENG":"Commencing strategic bombardment over the operation zone!","TWN":"現在開始對作戰區域進行戰略轟炸！"},"stage":{"bg":"SKY_RED","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_HYERION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"대강의 사정은 보고받았네.","JPN":"事情は大体聞いている。","ENG":"I've been briefed on the situation.","TWN":"我已經大致了解情況了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L45_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이번 작전, 두 사람 모두 고생 많았어.","JPN":"二人共、今回の作戦はご苦労だった。","ENG":"Good work, both of you. You've done well this mission.","TWN":"這次作戰你們兩個人都辛苦了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"정의를 실현하는 기사에게 당연한 일을 했을 뿐!","JPN":"正義を実現する騎士として当然のことをしたまでだ！","ENG":"We only did what's expected of knights of justice!","TWN":"我只是做了身為實現正義的騎士應該做的事！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"허나, 종자가 기뻐하니 이 몸도 기쁘오!","JPN":"だが、従者に喜んでもらえて私も嬉しいぞ！","ENG":"But since my squire is pleased, so am I!","TWN":"不過，看到手下這麼高興，本小姐也很開心！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_LAUGH"}}}},{"id":"L50_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"마, 로빈! 아무리 그래도 쌤한테 종자가 뭐고 종자가……!","JPN":"ロビン！　いくらなんでも先生に従者はないやろ、従者は……！","ENG":"Robin! You can't just call Teach a squire...!","TWN":"蘿蘋！再怎麼樣也不能叫老師手下吧……！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_LAUGH"}}}},{"id":"L3_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그리고…….","JPN":"そして……","ENG":"And...","TWN":"還有……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_ON","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"칸의 일은 무척 유감이라네. 관리국은 또다시 좋은 인재를 잃었군.","JPN":"カンのことは……残念だ。管理局はまたも優秀な人材を失ってしまった。","ENG":"Khan's passing is a great loss. The Administration has lost another fine talent.","TWN":"對於坎的離世我感到非常遺憾。管理局又失去一位優秀的人才。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_ON","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇다면, 자네가 캄파멘토의 새로운 시니어인가?","JPN":"では、君がカンパメントの新しいシニアかい？","ENG":"Then you're Campamento's new Senior?","TWN":"你就是坎帕門托的新Senior嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_ON","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_NULL_ON","text":{"KOREA":"네…….","JPN":"はい……","ENG":"Yes...","TWN":"是……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"네, 그럼 당신은 할아버지께 말로만 듣던 그 최고 관리자이신가요?","JPN":"はい。おじいさまからお話だけは聞いておりましたが、あなたが最高管理者ですか？","ENG":"\\"Yes, and you must be the Supreme Administrator I heard about from my grandfather?\\"","TWN":"是，那你就是爺爺口中常提到的最高管理者嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_NULL_ON","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L9_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"……라고 시니어 님께서 의문을 표하십니다.","JPN":"……と、シニア様が疑問を表しています。","ENG":"...is what the new Senior says with curiosity.","TWN":"……Senior小姐對此表示疑問。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_NULL_ON","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_NULL_ON","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"후후, 재미있는 친구로군.","JPN":"ふふ、変わったお嬢さんだな。","ENG":"Haha... what an amusing girl.","TWN":"呵呵，真是個有趣的人呢。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_NULL_ON","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네도 알다시피 이번 전조 현상에 의해서.","JPN":"君も知っての通り、今回の前兆現象によって……","ENG":"As you know, this omen phenomenon...","TWN":"正如你所見，因為這次的前兆現象，"},"stage":{"bg":"OMEN_CAMPAMENTO_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"캄파멘토의 관리 영역 70%가 정체불명의 나무뿌리에 의해 잠식되었네.","JPN":"カンパメントの管理領域の70％が謎の木の根に覆われてしまった。","ENG":"Seventy percent of Campamento's management area has already been overrun by unknown roots.","TWN":"坎帕門托的管理區域，有70%都被不明樹根侵蝕了。"},"stage":{"bg":"OMEN_CAMPAMENTO_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그리고 그 영역은 지금도 넓어지고 있어.","JPN":"そしてその領域は今も拡張しつつある。","ENG":"And it's continuing to spread.","TWN":"而且範圍還在不斷擴大。"},"stage":{"bg":"OMEN_CAMPAMENTO_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_NULL_ON","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그런 표정 짓지 말게. 자네 잘못이 아니라는 것쯤은 알고 있으니까.","JPN":"そんな顔をしないでくれ。君のせいではないことぐらい、私も分かっている。","ENG":"Don't wear that look. I know it isn't your fault.","TWN":"別露出那種表情，我知道這不是你的錯。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 이 시점에서 대책이 필요한 것도 사실이야.","JPN":"だが、そろそろ対策が必要なのも事実だ。","ENG":"But we do need countermeasures.","TWN":"但在這個時候，確實需要一個對策。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네들이 회수한 <color=#ffd34c>유해</color>에 대해서도 분석이 필요하고.","JPN":"君たちが回収した<color=#ffd34c>遺骸</color>も分析しないといけないしな。","ENG":"We must also analyze the <color=#ffd34c>remains</color> you've recovered.","TWN":"你們回收的<color=#ffd34c>遺骸</color>也需要進行分析。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"일단은, 모두들 내가 있는 <color=#ffd34c>로터스</color> 지부로 와주게.","JPN":"まずは皆、私がいる<color=#ffd34c>ロータス</color>支部まで来てくれたまえ。","ENG":"For now, come to the <color=#ffd34c>Lotus</color> branch where I am.","TWN":"大家先來我所在的<color=#ffd34c>洛德斯</color>分部吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그곳에서 이야기를 나누도록 하지.","JPN":"そこで話すとしよう。","ENG":"We'll discuss everything there.","TWN":"詳細情形等見面再聊。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}}]`);export{e as default};